env = Environment(loader=loader)
print('fs alias:', env.get_template('home').render())

try:
    env.get_template('missing')
except TemplateNotFound as e:
    print('fs not found name:', e.name)

# backward compat
loader2 = FileSystemLoader('/tmp/jinja_test/templates')
env2 = Environment(loader=loader2)
print('fs plain:', env2.get_template('index.html').render())
